W\_a&= \int\_{V\_i}^{V\_f} \frac{nRT}{V}.dV\\
W\_a&= nRT\ln\frac{V\_f}{V\_i}\\
W\_a&= \pu{2.35 \times 8.314 \times 300 \times \ln3 J}\\
W\_a&= \pu{6439.37 J}\\
\end{align}
\begin{align}
q\_a&= W\_a+ \Delta U\_a\\
